import React, { useState, useEffect } from 'react';
import { AdminService } from '../../../services/api';
import { Trash2, Plus, Hash, Layers, Loader2 } from 'lucide-react';
import toast from 'react-hot-toast';

export const AdminTaxonomy = () => {
  const [data, setData] = useState<any>({ themes: [], tags: [] });
  const [loading, setLoading] = useState(false);
  const [fetching, setFetching] = useState(true);

  // Manual addition states for both types
  const [newTheme, setNewTheme] = useState({ id: '', name: '' });
  const [newTag, setNewTag] = useState({ id: '', name: '' });

  const fetchTaxonomy = async () => {
    try {
      const res: any = await AdminService.getAllTaxonomy();
      setData(res.data?.data || { themes: [], tags: [] });
    } catch (err) {
      toast.error("Failed to sync taxonomy");
    } finally {
      setFetching(false);
    }
  };

  useEffect(() => { fetchTaxonomy(); }, []);

  const handleAdd = async (type: 'theme' | 'tag') => {
    // Mapping the data to match your specific Model keys
    const payload = type === 'theme' 
      ? { Theme_ID: newTheme.id, Theme_Name: newTheme.name, type } 
      : { Tag_ID: newTag.id, Tag_Name: newTag.name, type };

    if (!(type === 'theme' ? newTheme.id : newTag.id)) {
      return toast.error("ID is required (e.g., THEME001)");
    }

    setLoading(true);
    try {
      await AdminService.upsertTaxonomy(payload);
      toast.success(`${type} added to archive`);
      // Reset only the form that was submitted
      type === 'theme' ? setNewTheme({ id: '', name: '' }) : setNewTag({ id: '', name: '' });
      fetchTaxonomy();
    } catch (err) {
      toast.error("Save failed: Check for duplicate IDs");
    } finally {
      setLoading(false);
    }
  };

  const handleDelete = async (id: string, type: 'theme' | 'tag') => {
    if (!window.confirm(`Permanently remove this ${type}?`)) return;
    try {
      await AdminService.deleteTaxonomy(id, type);
      toast.success("Removed");
      fetchTaxonomy();
    } catch (err) {
      toast.error("Deletion failed");
    }
  };

  if (fetching) return (
    <div className="h-96 flex flex-col items-center justify-center text-primary">
      <Loader2 className="animate-spin mb-4" size={32} />
      <p className="text-[10px] font-black uppercase tracking-widest">Loading Taxonomy...</p>
    </div>
  );

  return (
    <div className="p-8 space-y-10 animate-in fade-in duration-700">
      <div>
        <h1 className="text-4xl font-black uppercase italic text-white">Taxonomy <span className="text-primary">Control</span></h1>
        <p className="text-gray-500 font-bold uppercase text-[10px] tracking-[0.3em] mt-1">Classification Management</p>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-10">
        
        {/* --- THEMES CONTROL --- */}
        <section className="space-y-6">
          <div className="bg-[#0f0f0f] p-8 rounded-[2.5rem] border border-white/5 space-y-4">
            <div className="flex items-center gap-2 mb-2">
              <Layers className="text-primary" size={18} />
              <h2 className="text-white font-black uppercase text-xs tracking-widest italic">Add New Theme</h2>
            </div>
            <div className="grid grid-cols-2 gap-2">
              <input value={newTheme.id} onChange={e => setNewTheme({...newTheme, id: e.target.value})} placeholder="ID (THEME001)" className="bg-white/5 border border-white/10 p-3 rounded-xl text-[10px] text-white outline-none focus:border-primary font-bold" />
              <input value={newTheme.name} onChange={e => setNewTheme({...newTheme, name: e.target.value})} placeholder="Theme Name" className="bg-white/5 border border-white/10 p-3 rounded-xl text-[10px] text-white outline-none focus:border-primary font-bold" />
            </div>
            <button onClick={() => handleAdd('theme')} disabled={loading} className="w-full bg-primary text-black py-3 rounded-xl font-black uppercase text-[10px] hover:bg-white transition-all">Commit Theme</button>
          </div>

          <div className="space-y-2 max-h-[400px] overflow-y-auto pr-2 custom-scrollbar">
            {data.themes?.map((t: any) => (
              <div key={t._id} className="p-4 bg-[#0f0f0f] rounded-2xl border border-white/5 flex justify-between items-center group">
                <div className="flex flex-col">
                  <span className="text-[8px] font-black text-primary uppercase tracking-tighter">{t.Theme_ID}</span>
                  <span className="font-bold text-xs uppercase text-white italic">{t.Theme_Name}</span>
                </div>
                <button onClick={() => handleDelete(t._id, 'theme')} className="p-2 text-gray-600 hover:text-red-500 transition-colors">
                  <Trash2 size={14} />
                </button>
              </div>
            ))}
          </div>
        </section>

        {/* --- TAGS CONTROL --- */}
        <section className="space-y-6">
          <div className="bg-[#0f0f0f] p-8 rounded-[2.5rem] border border-white/5 space-y-4">
            <div className="flex items-center gap-2 mb-2">
              <Hash className="text-primary" size={18} />
              <h2 className="text-white font-black uppercase text-xs tracking-widest italic">Add New Tag</h2>
            </div>
            <div className="grid grid-cols-2 gap-2">
              <input value={newTag.id} onChange={e => setNewTag({...newTag, id: e.target.value})} placeholder="ID (TAG001)" className="bg-white/5 border border-white/10 p-3 rounded-xl text-[10px] text-white outline-none focus:border-primary font-bold" />
              <input value={newTag.name} onChange={e => setNewTag({...newTag, name: e.target.value})} placeholder="Tag Name" className="bg-white/5 border border-white/10 p-3 rounded-xl text-[10px] text-white outline-none focus:border-primary font-bold" />
            </div>
            <button onClick={() => handleAdd('tag')} disabled={loading} className="w-full bg-primary text-black py-3 rounded-xl font-black uppercase text-[10px] hover:bg-white transition-all">Commit Tag</button>
          </div>

          <div className="flex flex-wrap gap-2">
            {data.tags?.map((t: any) => (
              <div key={t._id} className="group relative flex items-center bg-white/5 border border-white/10 rounded-xl pl-4 pr-2 py-2 hover:border-primary/50 transition-all">
                <span className="text-[10px] font-black uppercase tracking-tighter text-gray-300">
                  #{t.Tag_Name}
                </span>
                <button onClick={() => handleDelete(t._id, 'tag')} className="ml-2 p-1 text-gray-600 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-all">
                  <Trash2 size={10} />
                </button>
              </div>
            ))}
          </div>
        </section>
      </div>
    </div>
  );
};
